class TestValidSessionId:
    def test_valid_alphanumeric(self):
        assert prompt_log._valid_session_id("abc-123") is True

    def test_valid_uuid_like(self):
        uuid = "9a8dee8e-8e7f-4058-8df1-9d1c72e991bd"
        assert prompt_log._valid_session_id(uuid) is True

    def test_valid_underscore(self):
        assert prompt_log._valid_session_id("session_1") is True

    def test_rejects_empty(self):
        assert prompt_log._valid_session_id("") is False

    def test_rejects_path_traversal(self):
        assert prompt_log._valid_session_id("../etc/passwd") is False

    def test_rejects_slash(self):
        assert prompt_log._valid_session_id("foo/bar") is False

    def test_rejects_backslash(self):
        assert prompt_log._valid_session_id("foo\\bar") is False

    def test_rejects_space(self):
        assert prompt_log._valid_session_id("foo bar") is False

    def test_rejects_null_byte(self):
        assert prompt_log._valid_session_id("foo\x00bar") is False


class TestGitBranch:
    def test_returns_branch_name(self):
        result = mock.Mock()
        result.returncode = 0
        result.stdout = "feature-x\n"
        with mock.patch("prompt_log.subprocess.run", return_value=result) as mock_run:
            assert prompt_log._git_branch("/some/repo") == "feature-x"
            mock_run.assert_called_once()
            args = mock_run.call_args
            assert args[0][0] == ["git", "rev-parse", "--abbrev-ref", "HEAD"]
            assert args[1]["cwd"] == "/some/repo"

    def test_nonzero_exit_returns_empty(self):
        result = mock.Mock()
        result.returncode = 128
        result.stdout = ""
        with mock.patch("prompt_log.subprocess.run", return_value=result):
            assert prompt_log._git_branch("/not/a/repo") == ""

    def test_oserror_returns_empty(self):
        with mock.patch("prompt_log.subprocess.run", side_effect=OSError):
            assert prompt_log._git_branch("/some/path") == ""

    def test_timeout_returns_empty(self):
        from subprocess import TimeoutExpired

        with mock.patch(
            "prompt_log.subprocess.run", side_effect=TimeoutExpired("git", 2)
        ):
            assert prompt_log._git_branch("/some/path") == ""


