class TestMain:
    def test_prompt_event_writes_log(self, tmp_path, monkeypatch):
        data = {
            "hook_event_name": "UserPromptSubmit",
            "session_id": "sess-1",
            "cwd": "/home/user/project",
            "prompt": "What is this?",
        }
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        mock_dir = str(tmp_path / "prompt-log")
        with (
            mock.patch("prompt_log._git_branch", return_value="main"),
            mock.patch("prompt_log.PROMPT_LOG_DIR", mock_dir),
        ):
            prompt_log.main()

        log_dir = tmp_path / "prompt-log"
        jsonl_files = list(log_dir.rglob("*.jsonl"))
        assert len(jsonl_files) == 1
        line = json.loads(jsonl_files[0].read_text().strip())
        assert line["event_type"] == "prompt"
        assert line["content"] == "What is this?"

    def test_stop_event_writes_log(self, tmp_path, monkeypatch):
        data = {
            "hook_event_name": "Stop",
            "session_id": "sess-1",
            "cwd": "/home/user/project",
            "last_assistant_message": "Done.",
        }
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        mock_dir = str(tmp_path / "prompt-log")
        with (
            mock.patch("prompt_log._git_branch", return_value="main"),
            mock.patch("prompt_log.PROMPT_LOG_DIR", mock_dir),
        ):
            prompt_log.main()

        log_dir = tmp_path / "prompt-log"
        jsonl_files = list(log_dir.rglob("*.jsonl"))
        assert len(jsonl_files) == 1
        line = json.loads(jsonl_files[0].read_text().strip())
        assert line["event_type"] == "response"
        assert line["content"] == "Done."

    def test_question_event_writes_log(self, tmp_path, monkeypatch):
        data = {
            "hook_event_name": "PostToolUse",
            "tool_name": "AskUserQuestion",
            "session_id": "sess-1",
            "cwd": "/home/user/project",
            "tool_input": {
                "questions": [
                    {
                        "question": "Continue?",
                        "header": "Confirm",
                        "options": [
                            {"label": "yes", "description": "proceed"},
                            {"label": "no", "description": "stop"},
                        ],
                        "multiSelect": False,
                    }
                ],
                "answers": {"Continue?": "yes"},
            },
        }
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        mock_dir = str(tmp_path / "prompt-log")
        with (
            mock.patch("prompt_log._git_branch", return_value="main"),
            mock.patch("prompt_log.PROMPT_LOG_DIR", mock_dir),
        ):
            prompt_log.main()

        log_dir = tmp_path / "prompt-log"
        jsonl_files = list(log_dir.rglob("*.jsonl"))
        assert len(jsonl_files) == 1
        line = json.loads(jsonl_files[0].read_text().strip())
        assert line["event_type"] == "question"
        assert line["question"] == "Continue?"
        assert line["options"] == [
            {"label": "yes", "description": "proceed"},
            {"label": "no", "description": "stop"},
        ]
        assert line["answer"] == "yes"

